import{_ as n,c as a,o as e,a1 as t}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Установка: Быстрый старт за 5 минут | opencode-dcp","description":"Изучите методы установки плагина DCP. Завершите настройку за 5 минут, значительно сократите потребление токенов в длинных对话ах благодаря автоматической обрезке и улучшите качество ответов ИИ.","frontmatter":{"title":"Установка: Быстрый старт за 5 минут | opencode-dcp","sidebarTitle":"Запустите за 5 минут","subtitle":"Установка: Быстрый старт за 5 минут","description":"Изучите методы установки плагина DCP. Завершите настройку за 5 минут, значительно сократите потребление токенов в длинных对话ах благодаря автоматической обрезке и улучшите качество ответов ИИ.","tags":["Установка","Быстрый старт","DCP"],"prerequisite":["Установлен OpenCode"],"order":"1"},"headers":[],"relativePath":"ru/Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md","filePath":"ru/Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md"}'),o={name:"ru/Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md"};function i(l,s,p,d,c,r){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="установка-и-быстрыи-старт" tabindex="-1">Установка и быстрый старт <a class="header-anchor" href="#установка-и-быстрыи-старт" aria-label="Permalink to &quot;Установка и быстрый старт&quot;">​</a></h1><h2 id="что-вы-сможете-сделать-после-прохождения" tabindex="-1">Что вы сможете сделать после прохождения <a class="header-anchor" href="#что-вы-сможете-сделать-после-прохождения" aria-label="Permalink to &quot;Что вы сможете сделать после прохождения&quot;">​</a></h2><ul><li>✅ Установить плагин DCP за 5 минут</li><li>✅ Настроить плагин и проверить успешную установку</li><li>✅ Увидеть эффект первой автоматической обрезки</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Со временем использования OpenCode对话и становятся всё длиннее:</p><ul><li>ИИ многократно читает один и тот же файл</li><li>Сообщения об ошибках инструментов заполняют контекст</li><li>Каждый对话消耗ет много токенов</li><li><strong>Чем длиннее对话, тем медленнее ответы ИИ</strong></li></ul><p>Вы хотели бы автоматически очищать冗余内容 в对话е, но не хотите делать это вручную.</p><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p><strong>DCP (Dynamic Context Pruning)</strong> — это плагин OpenCode, который автоматически удаляет冗余ные инструменты из истории对话а и сокращает потребление токенов.</p><p>Как это работает:</p><ol><li><strong>Автоматическое обнаружение</strong>: Перед каждым сообщением自动чески анализирует историю对话а</li><li><strong>Интеллектуальная очистка</strong>: Удаляет重复ные инструменты, устаревшие ошибки, перезаписанные записи</li><li><strong>Управляемый ИИ</strong>: ИИ может主动но вызывать инструменты <code>discard</code> и <code>extract</code> для оптимизации контекста</li><li><strong>Прозрачность и контроль</strong>: Команда <code>/dcp</code> для просмотра статистики обрезки, ручной запуск очистки</li></ol><div class="tip custom-block"><p class="custom-block-title">Основные преимущества</p><ul><li><strong>Нулевые затраты</strong>: Автоматические стратегии не требуют вызовов LLM</li><li><strong>Нулевая настройка</strong>: Установил и используй, оптимизированные настройки по умолчанию</li><li><strong>Нулевой риск</strong>: Модифицируется только контекст, отправляемый LLM, история对话а не затрагивается</li></ul></div><h2 id="🎒-подготовка-перед-началом" tabindex="-1">🎒 Подготовка перед началом <a class="header-anchor" href="#🎒-подготовка-перед-началом" aria-label="Permalink to &quot;🎒 Подготовка перед началом&quot;">​</a></h2><p>Перед установкой убедитесь, что:</p><ul><li>[ ] Установлен <strong>OpenCode</strong> (поддерживает плагины)</li><li>[ ] Знаете, как редактировать <strong>конфигурационный файл OpenCode</strong></li><li>[ ] Понимаете базовый <strong>синтаксис JSONC</strong> (JSON с комментариями)</li></ul><div class="warning custom-block"><p class="custom-block-title">Важное напоминание</p><p>DCP изменяет контекст, отправляемый LLM, но не влияет на историю对话а. Вы можете отключить плагин в настройках в любое время.</p></div><h2 id="следуите-инструкциям" tabindex="-1">Следуйте инструкциям <a class="header-anchor" href="#следуите-инструкциям" aria-label="Permalink to &quot;Следуйте инструкциям&quot;">​</a></h2><h3 id="шаг-1-редактирование-конфигурационного-фаила-opencode" tabindex="-1">Шаг 1: Редактирование конфигурационного файла OpenCode <a class="header-anchor" href="#шаг-1-редактирование-конфигурационного-фаила-opencode" aria-label="Permalink to &quot;Шаг 1: Редактирование конфигурационного файла OpenCode&quot;">​</a></h3><p><strong>Зачем</strong> Нужно объявить плагин DCP в конфигурации OpenCode, чтобы OpenCode автоматически загружал его при запуске.</p><p>Откройте конфигурационный файл OpenCode <code>opencode.jsonc</code> и добавьте DCP в поле <code>plugin</code>:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// opencode.jsonc</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@tarquinen/opencode-dcp@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: В конфигурационном файле уже есть другие плагины (если есть), просто добавьте DCP в конец массива.</p><div class="info custom-block"><p class="custom-block-title">Подсказка</p><p>Используя тег <code>@latest</code>, OpenCode при каждом запуске будет автоматически проверять и загружать последнюю версию.</p></div><h3 id="шаг-2-перезапуск-opencode" tabindex="-1">Шаг 2: Перезапуск OpenCode <a class="header-anchor" href="#шаг-2-перезапуск-opencode" aria-label="Permalink to &quot;Шаг 2: Перезапуск OpenCode&quot;">​</a></h3><p><strong>Зачем</strong> Изменения конфигурации плагина требуют перезапуска для вступления в силу.</p><p>Полностью закройте OpenCode, затем перезапустите.</p><p><strong>Что вы должны увидеть</strong>: OpenCode запускается нормально, без сообщений об ошибках.</p><h3 id="шаг-3-проверка-установки-плагина" tabindex="-1">Шаг 3: Проверка установки плагина <a class="header-anchor" href="#шаг-3-проверка-установки-плагина" aria-label="Permalink to &quot;Шаг 3: Проверка установки плагина&quot;">​</a></h3><p><strong>Зачем</strong> Убедиться, что плагин DCP загружен правильно, и просмотреть конфигурацию по умолчанию.</p><p>Введите в对话е OpenCode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dcp</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: Справку по командам DCP, подтверждающую успешную установку плагина.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Commands                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /dcp context      Show token usage breakdown for current session</span></span>
<span class="line"><span>  /dcp stats        Show DCP pruning statistics</span></span>
<span class="line"><span>  /dcp sweep [n]    Prune tools since last user message, or last n tools</span></span></code></pre></div><h3 id="шаг-4-просмотр-конфигурации-по-умолчанию" tabindex="-1">Шаг 4: Просмотр конфигурации по умолчанию <a class="header-anchor" href="#шаг-4-просмотр-конфигурации-по-умолчанию" aria-label="Permalink to &quot;Шаг 4: Просмотр конфигурации по умолчанию&quot;">​</a></h3><p><strong>Зачем</strong> Понять конфигурацию DCP по умолчанию и убедиться, что плагин работает как ожидалось.</p><p>DCP автоматически создаст конфигурационный файл при первом запуске:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Просмотр глобального конфигурационного файла</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/dcp.jsonc</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: Конфигурационный файл создан, изначально содержит только поле <code>$schema</code>:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://raw.githubusercontent.com/Opencode-DCP/opencode-dynamic-context-pruning/master/dcp.schema.json&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Конфигурационный файл изначально содержит только поле <code>$schema</code>, все остальные настройки используют значения по умолчанию из кода, дополнительная настройка не требуется.</p><div class="tip custom-block"><p class="custom-block-title">Объяснение конфигурации по умолчанию</p><p>Значения DCP по умолчанию в коде (не нужно записывать в конфигурационный файл):</p><ul><li><strong>deduplication</strong>: Автоматическое удаление重复ных инструментов</li><li><strong>purgeErrors</strong>: Автоматическая очистка ошибок инструментов старше 4 раундов</li><li><strong>discard/extract</strong>: Инструменты обрезки, доступные ИИ</li><li><strong>pruneNotification</strong>: Показывать подробные уведомления об обрезке</li></ul><p>Если需要自定义配置, вы можете добавить эти поля вручную. Подробное описание конфигурации см. в разделе <a href="./../configuration/">Полная конфигурация</a>.</p></div><h3 id="шаг-5-体验自动修剪效果" tabindex="-1">Шаг 5:体验自动修剪效果 <a class="header-anchor" href="#шаг-5-体验自动修剪效果" aria-label="Permalink to &quot;Шаг 5:体验自动修剪效果&quot;">​</a></h3><p><strong>Зачем</strong> Практически использовать DCP и увидеть эффект автоматической обрезки.</p><p>Проведите一段对话 в OpenCode,让 ИИ несколько раз读取同一个文件, или выполните一些 инструменты, которые завершатся неудачей.</p><p><strong>Что вы должны увидеть</strong>:</p><ol><li>При каждой отправке сообщения DCP автоматически анализирует историю对话а</li><li>Если есть重复ные инструменты, DCP автоматически очищает их</li><li>После ответа ИИ могут появиться уведомления об обрезке (в зависимости от конфигурации <code>pruneNotification</code>)</li></ol><p>Пример уведомления об обрезке:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>▣ DCP | ~12.5K tokens saved total</span></span>
<span class="line"><span></span></span>
<span class="line"><span>▣ Pruning (~12.5K tokens)</span></span>
<span class="line"><span>→ read: src/config.ts</span></span>
<span class="line"><span>→ write: package.json</span></span></code></pre></div><p>Введите <code>/dcp context</code> для просмотра использования токенов в текущей сессии:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Session Context Breakdown:</span></span>
<span class="line"><span>───────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System         15.2% │████████████████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│  25.1K tokens</span></span>
<span class="line"><span>User            5.1% │████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│   8.4K tokens</span></span>
<span class="line"><span>Assistant       35.8% │██████████████████████████████████████▒▒▒▒▒▒▒│  59.2K tokens</span></span>
<span class="line"><span>Tools (45)      43.9% │████████████████████████████████████████████████│  72.6K tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>───────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary:</span></span>
<span class="line"><span>  Pruned:          12 tools (~15.2K tokens)</span></span>
<span class="line"><span>  Current context: ~165.3K tokens</span></span>
<span class="line"><span>  Without DCP:     ~180.5K tokens</span></span></code></pre></div><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>После выполнения всех шагов вы должны:</p><ul><li>[ ] Добавлен плагин DCP в <code>opencode.jsonc</code></li><li>[ ] OpenCode работает нормально после перезапуска</li><li>[ ] Команда <code>/dcp</code> отображает справочную информацию</li><li>[ ] Конфигурационный файл <code>~/.config/opencode/dcp.jsonc</code> создан</li><li>[ ] В对话е видны уведомления об обрезке или статистика через <code>/dcp context</code></li></ul><p><strong>Если какой-то шаг не удался</strong>:</p><ul><li>Проверьте правильность синтаксиса <code>opencode.jsonc</code> (формат JSONC)</li><li>Проверьте журналы OpenCode на наличие ошибок загрузки плагина</li><li>Убедитесь, что версия OpenCode поддерживает插件功能</li></ul><h2 id="⚠️提醒注意" tabindex="-1">⚠️提醒注意 <a class="header-anchor" href="#⚠️提醒注意" aria-label="Permalink to &quot;⚠️提醒注意&quot;">​</a></h2><h3 id="проблема-1-плагин-не-работает" tabindex="-1">Проблема 1: Плагин не работает <a class="header-anchor" href="#проблема-1-плагин-не-работает" aria-label="Permalink to &quot;Проблема 1: Плагин не работает&quot;">​</a></h3><p><strong>Симптомы</strong>: Конфигурация добавлена, но эффекта обрезки не видно</p><p><strong>Причина</strong>: OpenCode не перезапущен или неправильный путь к конфигурационному файлу</p><p><strong>Решение</strong>:</p><ol><li>Полностью закройте OpenCode и перезапустите</li><li>Проверьте правильность расположения <code>opencode.jsonc</code></li><li>Просмотрите журналы: файлы журналов в директории <code>~/.config/opencode/logs/dcp/daily/</code></li></ol><h3 id="проблема-2-конфигурационныи-фаил-не-создан" tabindex="-1">Проблема 2: Конфигурационный файл не создан <a class="header-anchor" href="#проблема-2-конфигурационныи-фаил-не-создан" aria-label="Permalink to &quot;Проблема 2: Конфигурационный файл не создан&quot;">​</a></h3><p><strong>Симптомы</strong>: <code>~/.config/opencode/dcp.jsonc</code> не существует</p><p><strong>Причина</strong>: OpenCode не вызывал плагин DCP или проблемы с правами доступа к директории</p><p><strong>Решение</strong>:</p><ol><li>Убедитесь, что OpenCode перезапущен</li><li>Создайте директорию конфигурации вручную: <code>mkdir -p ~/.config/opencode</code></li><li>Проверьте правильность имени плагина в <code>opencode.jsonc</code>: <code>@tarquinen/opencode-dcp@latest</code></li></ol><h3 id="проблема-3-уведомления-об-обрезке-не-отображаются" tabindex="-1">Проблема 3: Уведомления об обрезке не отображаются <a class="header-anchor" href="#проблема-3-уведомления-об-обрезке-не-отображаются" aria-label="Permalink to &quot;Проблема 3: Уведомления об обрезке не отображаются&quot;">​</a></h3><p><strong>Симптомы</strong>: Уведомления об обрезке не видны, но <code>/dcp stats</code> показывает обрезку</p><p><strong>Причина</strong>: <code>pruneNotification</code> настроен как <code>&quot;off&quot;</code> или <code>&quot;minimal&quot;</code></p><p><strong>Решение</strong>: Измените конфигурационный файл:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pruneNotification&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;detailed&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // или &quot;minimal&quot;</span></span></code></pre></div><h2 id="итоги-урока" tabindex="-1">Итоги урока <a class="header-anchor" href="#итоги-урока" aria-label="Permalink to &quot;Итоги урока&quot;">​</a></h2><p>Установка плагина DCP очень проста:</p><ol><li>Добавьте плагин в <code>opencode.jsonc</code></li><li>Перезапустите OpenCode</li><li>Используйте команду <code>/dcp</code> для проверки установки</li><li>Конфигурация по умолчанию готова к использованию, дополнительная настройка не требуется</li></ol><p><strong>Функции DCP, включенные по умолчанию</strong>:</p><ul><li>✅ Стратегия автоматического удаления дублей (удаление重复ных инструментов)</li><li>✅ Стратегия очистки ошибок (очистка устаревших错误输入)</li><li>✅ Инструменты, управляемые ИИ (<code>discard</code> и <code>extract</code>)</li><li>✅ Подробные уведомления об обрезке</li></ul><p><strong>Следующий шаг</strong>: Узнайте, как настроить конфигурацию и调整стратегии обрезки для различных сценариев.</p><hr><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../configuration/">Полную конфигурацию</a></strong></p><p>Вы узнаете:</p><ul><li>Многоуровневую систему конфигурации (глобальная, переменные окружения, уровень проекта)</li><li>Назначение и рекомендуемые настройки всех параметров конфигурации</li><li>Защита раундов, защищённые инструменты, защищённые файловые паттерны</li><li>Как включить/выключить различные стратегии обрезки</li></ul></blockquote><hr><h2 id="приложение-ссылка-на-исходныи-код" tabindex="-1">Приложение: Ссылка на исходный код <a class="header-anchor" href="#приложение-ссылка-на-исходныи-код" aria-label="Permalink to &quot;Приложение: Ссылка на исходный код&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>Вход плагина</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/index.ts" target="_blank" rel="noreferrer"><code>index.ts</code></a></td><td>12-102</td></tr><tr><td>Управление конфигурацией</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/config.ts" target="_blank" rel="noreferrer"><code>lib/config.ts</code></a></td><td>669-794</td></tr><tr><td>Обработка команд</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/help.ts" target="_blank" rel="noreferrer"><code>lib/commands/help.ts</code></a></td><td>1-40</td></tr><tr><td>Расчёт токенов</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>68-174</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>MAX_TOOL_CACHE_SIZE = 1000</code>: Максимальное количество записей в кэше инструментов</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>Plugin()</code>: Регистрация плагина и настройка хуков</li><li><code>getConfig()</code>: Загрузка и слияние многоуровневой конфигурации</li><li><code>handleContextCommand()</code>: Анализ использования токенов в текущей сессии</li></ul></details>`,83)])])}const u=n(o,[["render",i]]);export{g as __pageData,u as default};
